const { ethers } = require("ethers");

// Define provider and signer
const provider = new ethers.providers.Web3Provider(window.ethereum);
const signer = provider.getSigner();

// ERC20 Token contract ABI
const erc20Abi = [
    "function approve(address spender, uint256 amount) public returns (bool)",
    "function balanceOf(address account) view returns (uint256)",
    "function transfer(address recipient, uint256 amount) public returns (bool)"
];

// DEX contract ABI
const dexAbi = [
    "function swapTokens(address tokenIn, address tokenOut, uint256 amountIn, uint256 amountOutMin, address to, uint256 deadline) public returns (uint256 amountOut)"
];

// Token and DEX contract addresses
const tokenInAddress = "0xYourTokenInAddress";
const tokenOutAddress = "0xYourTokenOutAddress";
const dexAddress = "0xYourDexAddress";

// Maximum uint256 value
const maxUint256 = ethers.constants.MaxUint256;

async function approveToken(tokenAddress) {
    const tokenContract = new ethers.Contract(tokenAddress, erc20Abi, signer);
    const tx = await tokenContract.approve(dexAddress, maxUint256);
    await tx.wait();
    console.log("Approval successful for:", tokenAddress);
}

async function swapTokens(amountIn, amountOutMin) {
    const dexContract = new ethers.Contract(dexAddress, dexAbi, signer);
    const tx = await dexContract.swapTokens(tokenInAddress, tokenOutAddress, amountIn, amountOutMin, await signer.getAddress(), Math.floor(Date.now() / 1000) + 60 * 20);
    await tx.wait();
    console.log("Swap successful:", tx);
}

// Example usage
async function main() {
    await approveToken(tokenInAddress);
    const amountIn = ethers.utils.parseUnits("1.0", 18); // 1 token with 18 decimals
    const amountOutMin = ethers.utils.parseUnits("0.9", 18); // Minimum output amount
    await swapTokens(amountIn, amountOutMin);
}

